options.customCss:
/* This section adds the bold, neon effect to your title */
.n8n-form-html h1 {
    color: #ffffff;
    font-weight: bold; /* Makes the title bold as requested */
    text-align: center;
    margin-bottom: 20px; /* Adds some space below the title */
    /* Neon glow effect inspired by your banner */
    text-shadow:
        0 0 5px #fff,
        0 0 10px #fff,
        0 0 15px #33FF99,
        0 0 20px #33FF99,
        0 0 25px #33FF99,
        0 0 30px #33FF99;
}


:root {
	/* Font and size variables are kept as requested */
	--font-family: 'Open Sans', sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;
	--font-size-body: 12px;
	--font-size-label: 14px;
	--font-size-test-notice: 12px;
	--font-size-input: 14px;
	--font-size-header: 20px;
	--font-size-paragraph: 14px;
	--font-size-link: 12px;
	--font-size-error: 12px;
	--font-size-html-h1: 28px;
	--font-size-html-h2: 20px;
	--font-size-html-h3: 16px;
	--font-size-html-h4: 14px;
	--font-size-html-h5: 12px;
	--font-size-html-h6: 10px;
	--font-size-subheader: 14px;

	/* Colors - Updated to match your banner's futuristic/neon theme */
	--color-background: #100E19; /* Dark space background */
	--color-card-bg: #1C1A2A; /* Slightly lighter card background */
	--color-card-border: #8A2BE2; /* Purple accent for borders */
	--color-card-shadow: rgba(51, 255, 153, 0.15); /* Neon green glow */
	--color-header: #F0F0F0; /* Main header text color (title is styled separately) */
	--color-label: #E0E0E0; /* Light text for labels */
	--color-input-border: #4a4a6a; /* Muted purple for input borders */
	--color-input-text: #000000; /* Black text for inside inputs (CHANGED AS REQUESTED) */
	--color-focus-border: #33FF99; /* Neon green for focus highlight */
	--color-submit-btn-bg: #33FF99; /* Neon green submit button */
	--color-submit-btn-text: #100E19; /* Dark text on button for contrast */
	--color-link: #A78BFA; /* Lighter purple for links */
	--color-html-text: #F0F0F0; /* General text color */
	--color-html-link: #33FF99; /* Neon green for links in HTML blocks */
	--color-header-subtext: #A0A0A0; /* Dimmer grey for sub-headers */
	--color-required: #33FF99; /* Neon green for required field indicators */
	--color-error: #FF4747; /* A bright red that fits the neon theme for errors */
	--color-clear-button-bg: #7e8186;

	/* Test notice colors - themed just in case */
	--color-test-notice-text: #33FF99;
	--color-test-notice-bg: #2a223a;
	--color-test-notice-border: #8A2BE2;

	/* Border Radii, Spacing, Dimensions, Others are kept as requested */
	--border-radius-card: 8px;
	--border-radius-input: 6px;
	--border-radius-clear-btn: 50%;
	--card-border-radius: 8px;
	--padding-container-top: 24px;
	--padding-card: 24px;
	--padding-test-notice-vertical: 12px;
	--padding-test-notice-horizontal: 24px;
	--margin-bottom-card: 16px;
	--padding-form-input: 12px;
	--card-padding: 24px;
	--card-margin-bottom: 16px;
	--container-width: 448px;
	--submit-btn-height: 48px;
	--checkbox-size: 18px;
	--box-shadow-card: 0px 4px 16px 0px var(--color-card-shadow);
	--opacity-placeholder: 0.5;
}

/* --- Black Placeholder Text --- */
.n8n-form-field-input::placeholder,
textarea::placeholder {
  color: #000000 !important;
  opacity: 1 !important;
}

.n8n-form-field-input::-moz-placeholder,
textarea::-moz-placeholder {
  color: #000000 !important;
  opacity: 1 !important;
}

.n8n-form-field-input:-ms-input-placeholder,
textarea:-ms-input-placeholder {
  color: #000000 !important;
  opacity: 1 !important;
}

.n8n-form-field-input::-webkit-input-placeholder,
textarea::-webkit-input-placeholder {
  color: #000000 !important;
  opacity: 1 !important;
}

